mapper.select:
SELECT

FROM (
    SELECT *
    FROM t_memory_entry
    WHERE session_id = #{sessionId}
      AND memory_type = #{memoryType}
    ORDER BY created_at DESC
    LIMIT #{limit}
) AS recent
ORDER BY created_at ASC

SELECT

FROM t_memory_entry
WHERE session_id = #{sessionId}
  AND memory_type = #{memoryType}

    AND importance >= #{minImportance}

ORDER BY importance DESC, created_at DESC
LIMIT #{limit}

SELECT

FROM t_memory_entry
WHERE session_id = #{sessionId}
  AND memory_type = #{memoryType}
  AND updated_at < #{before}
ORDER BY updated_at ASC
LIMIT #{limit}

SELECT COUNT(*)
FROM t_memory_entry
WHERE session_id = #{sessionId}
  AND memory_type = #{memoryType}
